import { useState } from 'react';

export default function Project({ title, description, image }) {
  const [flipped, setFlipped] = useState(false);

  return (
    <button
      type="button"
      className={`project-card ${flipped ? 'flipped' : ''}`}
      onClick={() => setFlipped((current) => !current)}
      aria-pressed={flipped}
    >
      <div className="project-card-inner">
        <div
          className="project-card-front"
          style={{ backgroundImage: `url(${image})` }}
        >
          <span className="project-card-label">Tap to flip</span>
        </div>

        <div className="project-card-back">
          <div className="project-card-content">
            <h4>{title}</h4>
            <p>{description}</p>
            <span className="project-card-btn">See more</span>
          </div>
        </div>
      </div>
    </button>
  );
}
